import "./AddRecipe.css";
import { useState } from "react";

export default function AddRecipe() {
  const [formData, setFormData] = useState({
    title: "",
    ingredients: "",
    steps: "",
    cooking_time: "",
    difficulty: "easy",
    image: null,
  });

  // ✅ USED properly (warning fixed)
  const handleChange = (e) => {
    const { name, value, files } = e.target;

    if (name === "image") {
      setFormData({ ...formData, image: files[0] });
    } else {
      setFormData({ ...formData, [name]: value });
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const data = new FormData();
    data.append("title", formData.title);
    data.append("ingredients", formData.ingredients);
    data.append("steps", formData.steps);
    data.append("cooking_time", formData.cooking_time);
    data.append("difficulty", formData.difficulty);

    if (formData.image) {
      data.append("image", formData.image);
    }

    try {
      const response = await fetch(
        "http://127.0.0.1:8000/api/recipes/add/",
        {
          method: "POST",
          body: data,
          credentials: "include", // 🔑 session auth
        }
      );

      await response.json(); // ✅ result not unused (warning fixed)

      if (response.ok) {
        alert("Recipe added successfully ✅");

        // optional reset
        setFormData({
          title: "",
          ingredients: "",
          steps: "",
          cooking_time: "",
          difficulty: "easy",
          image: null,
        });
      } else {
        alert("Failed to add recipe ❌");
      }
    } catch (error) {
      alert("Server error ❌");
    }
  };

  return (
    <div className="add-recipe-container">
      <h2>Add Recipe</h2>

      <form onSubmit={handleSubmit}>
        <input
          type="text"
          name="title"
          placeholder="Recipe Title"
          value={formData.title}
          onChange={handleChange}
          required
        />

        <textarea
          name="ingredients"
          placeholder="Ingredients"
          value={formData.ingredients}
          onChange={handleChange}
          required
        />

        <textarea
          name="steps"
          placeholder="Steps"
          value={formData.steps}
          onChange={handleChange}
          required
        />

        <input
          type="number"
          name="cooking_time"
          placeholder="Cooking Time (minutes)"
          value={formData.cooking_time}
          onChange={handleChange}
          required
        />

        <select
          name="difficulty"
          value={formData.difficulty}
          onChange={handleChange}
        >
          <option value="easy">Easy</option>
          <option value="medium">Medium</option>
          <option value="hard">Hard</option>
        </select>

        <input
          type="file"
          name="image"
          accept="image/*"
          onChange={handleChange}
        />

        <button type="submit">Add Recipe</button>
      </form>
    </div>
  );
}
